script:
contract_name = frappe.form_dict.get("contract_name")
doc = frappe.get_doc("Labour Contract", contract_name)

if doc.journal_entry:
    frappe.throw("Journal Entry already exists: " + doc.journal_entry)
if not doc.total_wage_bill:
    frappe.throw("Total Wage Bill is zero. Cannot create Journal Entry.")

expense_account = frappe.db.get_single_value("Agriculture Settings", "labour_expense_account")
cash_account = frappe.db.get_single_value("Agriculture Settings", "default_cash_account")

if not expense_account or not cash_account:
    frappe.throw("Please configure Labour Expense Account and Cash Account in Agriculture Settings.")

project = None
if doc.crop_cycle:
    project = frappe.db.get_value("Crop Cycle", doc.crop_cycle, "project")

je = frappe.get_doc({
    "doctype": "Journal Entry",
    "posting_date": frappe.utils.nowdate(),
    "user_remark": "Wage bill for " + doc.contract_name,
    "accounts": [
        {
            "account": expense_account,
            "debit_in_account_currency": doc.total_wage_bill,
            "project": project
        },
        {
            "account": cash_account,
            "credit_in_account_currency": doc.total_wage_bill
        }
    ]
})
je.insert()
doc.db_set("journal_entry", je.name)
frappe.response["message"] = je.name

if doc.issue_from_stock and not doc.stock_entry:
    if not doc.warehouse:
        frappe.throw("Please specify a Warehouse to issue stock from.")

    se = frappe.get_doc({
        "doctype": "Stock Entry",
        "stock_entry_type": "Material Issue",
        "company": frappe.db.get_default("company"),
        "from_warehouse": doc.warehouse,
        "items": [{
            "item_code": doc.item,
            "qty": doc.qty_used,
            "uom": doc.uom,
            "warehouse": doc.warehouse
        }]
    })
    se.insert()
    se.submit()
    doc.db_set("stock_entry", se.name)

if doc.starting_odometer and doc.ending_odometer:
    if doc.ending_odometer < doc.starting_odometer:
        frappe.throw("Ending Odometer cannot be less than Starting Odometer")

pending_tasks = frappe.get_all("Task",
    filters={
        "status": ["not in", ["Completed", "Cancelled"]],
        "exp_start_date": ["<=", frappe.utils.today()]
    },
    fields=["name", "subject", "project", "exp_start_date"]
)

if pending_tasks:
    tasks_by_project = {}
    for task in pending_tasks:
        tasks_by_project.setdefault(task.project, []).append(task)

    for project, tasks in tasks_by_project.items():
        crop_cycle = frappe.db.get_value("Crop Cycle", {"project": project}, "name")
        if not crop_cycle:
            continue

        message = "You have {} pending tasks for Crop Cycle {}:\n\n".format(len(tasks), crop_cycle)
        for task in tasks:
            message += "- {} ({})\n".format(task.subject, task.name)

        users = frappe.get_all("Has Role",
            filters={"role": ["in", ["Agriculture Manager", "Agriculture User"]], "parenttype": "User"},
            fields=["parent"],
            group_by="parent"
        )
        for user in users:
            if not frappe.db.get_value("User", user.parent, "enabled"):
                continue
            frappe.get_doc({
                "doctype": "Notification Log",
                "for_user": user.parent,
                "subject": "Daily Agricultural Alert",
                "email_content": message,
                "document_type": "Crop Cycle",
                "document_name": crop_cycle
            }).insert(ignore_permissions=True)

    frappe.db.commit()
